// ===== EDIT YOUR SETTINGS HERE =====
const YOUR_EMAIL = 'user@example.com';
const RSS_FEEDS = [
  'https://feeds.feedburner.com/TechCrunch',
  'https://hnrss.org/frontpage',
];
const MAX_ARTICLES = 15;
const HOURS_BACK = 24;

return RSS_FEEDS.map((feedUrl) => ({
  json: {
    feedUrl,
    recipientEmail: YOUR_EMAIL,
    maxArticles: MAX_ARTICLES,
    hoursBack: HOURS_BACK,
  },
}));

const config = $('Configure Feed Settings').first().json;
const maxArticles = config.maxArticles ?? 15;
const hoursBack = config.hoursBack ?? 24;
const cutoff = Date.now() - hoursBack * 60 * 60 * 1000;

const items = $input.all();
const seen = new Set();

const articles = items
  .map((item) => item.json)
  .filter((article) => {
    const link = article.link || article.guid || article.id;
    if (!link || seen.has(link)) {
      return false;
    }

    seen.add(link);

    const published = new Date(
      article.pubDate || article.isoDate || article.published || article.updated || 0,
    ).getTime();

    if (Number.isNaN(published)) {
      return true;
    }

    return published >= cutoff;
  })
  .sort((a, b) => {
    const dateA = new Date(a.pubDate || a.isoDate || a.published || 0).getTime();
    const dateB = new Date(b.pubDate || b.isoDate || b.published || 0).getTime();
    return dateB - dateA;
  })
  .slice(0, maxArticles);

return articles.map((article) => ({ json: article }));

const articles = $input.all().map((item) => item.json);
const config = $('Configure Feed Settings').first().json;

const today = new Date().toLocaleDateString('en-US', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric',
});

const escapeHtml = (value) =>
  String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');

const rows = articles
  .map((article) => {
    const title = escapeHtml(article.title || 'Untitled');
    const link = escapeHtml(article.link || article.guid || '#');
    const author = escapeHtml(
      article.creator || article.author || article['dc:creator'] || 'Unknown source',
    );
    const published = article.pubDate || article.isoDate || article.published;
    const dateLabel = published
      ? new Date(published).toLocaleString('en-US', {
          month: 'short',
          day: 'numeric',
          hour: 'numeric',
          minute: '2-digit',
        })
      : '';
    const snippet = escapeHtml(
      (article.contentSnippet || article.summary || article.description || '')
        .replace(/<[^>]*>/g, ' ')
        .trim()
        .slice(0, 180),
    );

    return `
      <tr>
        <td style="padding: 16px 0; border-bottom: 1px solid #e5e7eb;">
          <a href="${link}" style="color: #111827; font-size: 16px; font-weight: 600; text-decoration: none;">${title}</a>
          <div style="color: #6b7280; font-size: 12px; margin-top: 6px;">${author}${dateLabel ? ` · ${dateLabel}` : ''}</div>
          ${snippet ? `<div style="color: #374151; font-size: 14px; margin-top: 8px; line-height: 1.5;">${snippet}${snippet.length >= 180 ? '…' : ''}</div>` : ''}
        </td>
      </tr>
    `;
  })
  .join('');

const html = `
  <div style="font-family: Arial, sans-serif; max-width: 640px; margin: 0 auto; color: #111827;">
    <h1 style="font-size: 24px; margin-bottom: 8px;">Your Daily Digest</h1>
    <p style="color: #6b7280; margin-top: 0;">${today} · ${articles.length} article${articles.length === 1 ? '' : 's'}</p>
    <table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="border-collapse: collapse;">
      ${rows}
    </table>
  </div>
`;

return [
  {
    json: {
      subject: `Daily Digest — ${today}`,
      html,
      articleCount: articles.length,
      recipientEmail: config.recipientEmail,
    },
  },
];
